const ROWS = [
  {
    n: "01",
    title: "Workshops, not lectures",
    body: "You learn by making. Every course ends with something printed, bound, or built — not a grade on a screen.",
    shape: "circle",
    color: "bg-primary",
  },
  {
    n: "02",
    title: "Masters who still make",
    body: "Taught by working designers. The people marking your work ship theirs every week.",
    shape: "square",
    color: "bg-secondary",
  },
  {
    n: "03",
    title: "One language, three colours",
    body: "Constraint is the point. With a circle, a square, and three primaries you can say almost anything.",
    shape: "triangle",
    color: "bg-accent",
  },
]

function Shape({ kind }: { kind: string }) {
  if (kind === "circle") return <span className="size-12 rounded-full bg-foreground" />
  if (kind === "square") return <span className="size-12 bg-foreground" />
  return <span aria-hidden className="h-0 w-0 border-x-[24px] border-b-[42px] border-x-transparent border-b-foreground" />
}

/**
 * Bauhaus features — numbered rows with a flat color block and a hard shape.
 */
export function FeatureBauhaus() {
  return (
    <section className="border-b-4 border-foreground bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-5xl divide-y-2 divide-foreground border-y-2 border-foreground">
        {ROWS.map((r) => (
          <div key={r.n} className="grid items-center gap-6 py-8 sm:grid-cols-[auto_1fr_auto] sm:gap-10">
            <span className="text-5xl font-black tracking-tighter text-primary">{r.n}</span>
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tight">{r.title}</h3>
              <p className="mt-2 max-w-xl font-medium leading-relaxed text-muted-foreground">{r.body}</p>
            </div>
            <div className={`hidden size-24 place-items-center border-2 border-foreground sm:grid ${r.color}`}>
              <Shape kind={r.shape} />
            </div>
          </div>
        ))}
      </div>
    </section>
  )
}

"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform } from "framer-motion"

/**
 * Bauhaus parallax — a statement band where primary shapes drift on scroll.
 */
export function ParallaxBauhaus() {
  const ref = useRef<HTMLDivElement>(null)
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] })

  const y1 = useTransform(scrollYProgress, [0, 1], ["-40%", "40%"])
  const y2 = useTransform(scrollYProgress, [0, 1], ["30%", "-30%"])
  const rotate = useTransform(scrollYProgress, [0, 1], [0, 90])

  return (
    <section
      ref={ref}
      className="relative grid min-h-[440px] place-items-center overflow-hidden border-b-4 border-foreground bg-accent px-5 py-20 text-foreground"
    >
      <motion.span style={{ y: y1 }} aria-hidden className="pointer-events-none absolute left-[8%] top-10 size-28 rounded-full bg-primary" />
      <motion.span style={{ y: y2, rotate }} aria-hidden className="pointer-events-none absolute right-[10%] bottom-10 size-24 bg-secondary" />
      <motion.span
        style={{ y: y2 }}
        aria-hidden
        className="pointer-events-none absolute left-[18%] bottom-12 h-0 w-0 border-x-[26px] border-b-[46px] border-x-transparent border-b-foreground"
      />

      <div className="relative max-w-3xl text-center">
        <p className="font-mono text-xs tracking-[0.3em] uppercase">Werkbund Manifesto</p>
        <h2 className="mt-4 text-[clamp(2rem,7vw,5rem)] font-black leading-[0.92] tracking-tighter uppercase">
          Less, but better.
        </h2>
      </div>
    </section>
  )
}

const QUOTES = [
  {
    quote: "I arrived able to draw and left able to think. The workshop floor changed how I see everything.",
    name: "Anni T.",
    role: "Textile, class of '21",
    big: true,
  },
  { quote: "Three colours and a grid. I have never felt so free.", name: "Josef A.", role: "Print" },
  { quote: "They mark what you make, not what you say. It keeps you honest.", name: "Marcel B.", role: "Furniture" },
  { quote: "The best brief I ever got was: remove something.", name: "Lyonel F.", role: "Type" },
]

/**
 * Bauhaus testimonials — one flat-color pull-quote over a keyline review grid.
 */
export function TestimonialsBauhaus() {
  const [lead, ...rest] = QUOTES
  return (
    <section className="border-b-4 border-foreground bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl">
        <div className="border-2 border-foreground bg-secondary p-7 text-secondary-foreground sm:p-10">
          <p className="text-[clamp(1.5rem,4vw,3rem)] font-black leading-[1.02] tracking-tight uppercase">
            &ldquo;{lead.quote}&rdquo;
          </p>
          <p className="mt-6 font-mono text-sm font-bold uppercase">
            {lead.name} — {lead.role}
          </p>
        </div>

        <div className="mt-0 grid gap-0 border-x-2 border-b-2 border-foreground md:grid-cols-3">
          {rest.map((q) => (
            <figure
              key={q.name}
              className="border-foreground p-6 [&:not(:last-child)]:border-b-2 md:[&:not(:last-child)]:border-b-0 md:[&:not(:last-child)]:border-r-2"
            >
              <blockquote className="text-base font-bold leading-snug">&ldquo;{q.quote}&rdquo;</blockquote>
              <figcaption className="mt-4 font-mono text-xs font-bold uppercase text-muted-foreground">
                {q.name} · {q.role}
              </figcaption>
            </figure>
          ))}
        </div>
      </div>
    </section>
  )
}

import { Check } from "lucide-react"

const PLANS = [
  {
    name: "Evening",
    price: "1,200",
    blurb: "One module, after hours.",
    points: ["8 weekly workshops", "Studio access", "Final print"],
    color: "bg-card",
    featured: false,
  },
  {
    name: "Diploma",
    price: "4,800",
    blurb: "The full foundation year.",
    points: ["All four modules", "Dedicated bench", "Materials kit", "Degree show", "Mentor"],
    color: "bg-primary text-primary-foreground",
    featured: true,
  },
  {
    name: "Masters",
    price: "7,400",
    blurb: "Two years, your own brief.",
    points: ["Everything in Diploma", "Private studio", "Visiting critics", "Published monograph"],
    color: "bg-card",
    featured: false,
  },
]

/**
 * Bauhaus pricing — flat-color plan cards in a thick-keyline frame.
 */
export function PricingBauhaus() {
  return (
    <section className="border-b-4 border-foreground bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl">
        <h2 className="text-center text-[clamp(2rem,5vw,3.5rem)] font-black uppercase tracking-tighter">
          Pick a programme
        </h2>

        <div className="mt-12 grid gap-0 border-2 border-foreground md:grid-cols-3">
          {PLANS.map((p) => (
            <div
              key={p.name}
              className={`flex flex-col border-foreground p-6 md:[&:not(:last-child)]:border-r-2 [&:not(:last-child)]:border-b-2 md:[&:not(:last-child)]:border-b-0 ${p.color}`}
            >
              <div className="flex items-center justify-between">
                <p className="text-xl font-black uppercase">{p.name}</p>
                {p.featured && (
                  <span className="border-2 border-primary-foreground bg-accent px-2 py-0.5 font-mono text-[10px] font-bold uppercase text-foreground">
                    Popular
                  </span>
                )}
              </div>
              <p className={`mt-2 text-sm font-medium ${p.featured ? "text-primary-foreground/85" : "text-muted-foreground"}`}>
                {p.blurb}
              </p>
              <p className="mt-6 text-5xl font-black tracking-tighter">${p.price}</p>
              <ul className="mt-6 flex-1 space-y-2">
                {p.points.map((pt) => (
                  <li key={pt} className="flex items-center gap-2 text-sm font-bold uppercase">
                    <Check className="size-4 shrink-0" />
                    {pt}
                  </li>
                ))}
              </ul>
              <button
                className={`mt-6 border-2 py-3 text-sm font-black uppercase transition-colors ${
                  p.featured
                    ? "border-primary-foreground bg-accent text-foreground hover:bg-background"
                    : "border-foreground bg-secondary text-secondary-foreground hover:bg-foreground"
                }`}
              >
                Apply
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
